import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"键盘·鼠标","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/键鼠.md","filePath":"ccc/电脑/键鼠.md"}`),a={name:`ccc/电脑/键鼠.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="键盘·鼠标" tabindex="-1">键盘·鼠标 <a class="header-anchor" href="#键盘·鼠标" aria-label="Permalink to “键盘·鼠标”">​</a></h1><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>  外设体验没有绝对的好也没有绝对的坏，通常只能对客观参数进行介绍，体验相当主观。</span></span></code></pre></div><p>2023.7.8</p><p>鼠标</p><p><a href="https://sensor.fyi/mice/" target="_blank" rel="noreferrer">鼠标三围和传感器数据</a></p><h2 id="鼠标" tabindex="-1">鼠标 <a class="header-anchor" href="#鼠标" aria-label="Permalink to “鼠标”">​</a></h2><p>3325，3327对手臂流性能不够，3330及更高性能的传感器已超出手臂流需要的性能。</p><ul><li>ATK X1</li></ul><blockquote><p>VGN在我看来是中国第一家称得上游戏鼠标品牌。其他如雷柏，达尔优，富勒，多彩等品牌做了好几年，还是攒电脑的组装厂思维。ATK HUB驱动面板第一次不是公版驱动换皮，提供了直线修匀开关，波动修正开关，禁用可调刷新率，光传感器的高功耗或低功耗模式切换。</p><p>不过ATK的品控，细节可能不是最理想。</p></blockquote><ul><li>雷蛇·炼狱蝰蛇</li></ul><blockquote><p>中大手趴握强烈推荐。标准版传感器其实也够用，无非就是延迟高一点，有直线修匀。小手趴握，个人建议试试八岐大蛇。</p></blockquote><h2 id="smoothing" tabindex="-1">Smoothing <a class="header-anchor" href="#smoothing" aria-label="Permalink to “Smoothing”">​</a></h2><p>  鼠标的平滑修匀，光学传感器或主控会将行进的曲线修正成直线，这个过程会产生延迟。</p><ul><li>PAW3399</li></ul><p>  所有dpi没有sensor smoothing，3370和3399实际上是同一代产品，但是没有实测数据，不好说。</p><ul><li>PMW3389/PAW3390/PMW3360</li></ul><p>  1800dpi及以下2 frams smoothing(0.4ms)；1800以上dpi 有32frames smoothing(6.4ms)</p><ul><li>PMW3366</li></ul><p>  所有dpi 有2 frams smoothing（0.4ms）</p><ul><li>Mercury</li></ul><p>  所有dpi 没有 frams smoothing</p><ul><li>Hero 16K</li></ul><p>  所有dpi 没有 frams smoothing</p><ul><li>AM010</li></ul><p>  g302.g402在2000dpi以下有2 frams smoothing(0.4ms)2000以上有4 frames smoothing(0.8ms)</p><p>  g100s在所有dpi有4 frames smoothing(0.8ms)</p><h2 id="键盘" tabindex="-1">键盘 <a class="header-anchor" href="#键盘" aria-label="Permalink to “键盘”">​</a></h2><p>  传统轴寿命长短全看镀金层的厚薄，可再厚还是会有磨损，所以过个两三年总有几个轴会犯病。而光轴就不存在这个问题，可以一直用到主控报废。比如网鱼网吧就用光轴。</p><p>现在还有磁轴，百来块。</p><h3 id="文字工作者·静电容" tabindex="-1">文字工作者·静电容 <a class="header-anchor" href="#文字工作者·静电容" aria-label="Permalink to “文字工作者·静电容”">​</a></h3><p>  一些网络写手出现键盘手的症状后改用静电容加每天按摩热敷，症状有一定改善。推荐NIZ宁芝。</p><h3 id="樱桃轴选什么牌子" tabindex="-1">樱桃轴选什么牌子？ <a class="header-anchor" href="#樱桃轴选什么牌子" aria-label="Permalink to “樱桃轴选什么牌子？”">​</a></h3><p>富勒=高斯=斐尔可=海盗船=铁修罗=诺普=Ducky=钛度=ikbc=一切用cherry轴的键盘</p><p>ikbc由信必成代工，而高斯也是由其代工，ikbc和高斯哪个便宜买哪个。</p><p>  斐尔可和海盗船以及雷蛇等品牌溢价那么多，那都是无耻！<strong>用高价让你以为玄学手感会好！但事实上</strong>提供的体验和别的樱桃轴键盘没任何区别。他们用一样的pcb板，一样采购的轴，一样的主控是一个客观事实，不受主观意志转移。</p><p>  厂家除了推出APP，就只会在外壳和键帽上做文章。所以选择品牌应该看：</p><ul><li>哪个颜值打动你，如阿米洛的樱。</li><li>哪个更人性化，比如海盗船k68的防泼水。</li><li>哪个原厂键帽手感更好。</li><li>哪个性价比最高。</li></ul><h3 id="选什么轴体" tabindex="-1">选什么轴体 <a class="header-anchor" href="#选什么轴体" aria-label="Permalink to “选什么轴体”">​</a></h3><p>  黑轴摁久了累，理论上伤关节，青轴太吵。茶红的主要区别是茶轴有段落感。极限击打的速度，青轴会慢一点，茶红表现差不多，茶或红对游戏的适用性差不多。</p>`,39)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};